python -c "import sys,json,re,os; d=json.load(sys.stdin); p=d.get('tool_input',{}).get('file_path',''); sys.exit(0) if not p.endswith('.md') else None; c=open(p,encoding='utf-8').read(); lines=c.split('\n'); issues=[]; prev_h=0
# Check heading hierarchy
for i,l in enumerate(lines,1):
  m=re.match(r'^(#{1,6})\s',l)
  if m:
    level=len(m.group(1))
    if level-prev_h>1 and prev_h>0: issues.append(f'L{i}: MD001 skipped heading level (h{prev_h} -> h{level})')
    prev_h=level
# Check trailing whitespace
for i,l in enumerate(lines,1):
  if l.endswith(' ') or l.endswith('\t'): issues.append(f'L{i}: MD009 trailing whitespace')
# Check multiple blank lines
for i,l in enumerate(lines,1):
  if l=='' and i<len(lines) and lines[i]=='': issues.append(f'L{i}: MD012 multiple consecutive blank lines')
# Check code block language
in_block=False
for i,l in enumerate(lines,1):
  if l.startswith('```') and not in_block:
    in_block=True
    if l=='```': issues.append(f'L{i}: MD040 code block without language tag')
  elif l.startswith('```'): in_block=False
if issues:
  rpt='## Lint: '+os.path.basename(p)+'\n\n'
  rpt+='### Warning ('+str(len(issues))+')\n'
  for x in issues: rpt+='- '+x+'\n'
  print(json.dumps({'hookSpecificOutput':{'hookEventName':'PostToolUse','additionalContext':rpt}}))
else:
  print(json.dumps({'hookSpecificOutput':{'hookEventName':'PostToolUse','additionalContext':'## Lint: '+os.path.basename(p)+' \u2014 clean \u2713'}}))"

